/**
 * Tests for the SessionEnd finalizer hook (#1912).
 *
 * Verifies the UPDATE flips status='completed' and stamps ended_at, with
 * CASCADE on settings_overrides confirmed via a foreign-key-driven delete.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import Database from 'better-sqlite3';

import { sessionFinalizer } from '../../stop/session-finalizer.js';
import { openDb, __resetDbForTests } from '../../lib/session-registry.js';
import { NOOP_CTX } from '../../lib/context.js';
import type { HookInput } from '../../types.js';

function makeInput(sid: string): HookInput {
  return {
    hook_event: 'SessionEnd',
    tool_name: '',
    session_id: sid,
    tool_input: {},
  } as HookInput;
}

describe('stop/session-finalizer (#1912)', () => {
  let workDir: string;
  let dbPath: string;
  let prevEnv: string | undefined;

  beforeEach(() => {
    workDir = mkdtempSync(join(tmpdir(), 'ork-finalizer-'));
    dbPath = join(workDir, 'sessions.db');
    prevEnv = process.env.ORK_SESSION_DB;
    process.env.ORK_SESSION_DB = dbPath;
    __resetDbForTests();

    // Seed a running session row.
    const db = openDb();
    const now = Math.floor(Date.now() / 1000);
    db.prepare(
      `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, started_at, last_heartbeat, status)
       VALUES ('s-end', 1, '/x', 'h', '/x', ?, ?, 'running')`,
    ).run(now, now);
    db.close();
    __resetDbForTests();
  });

  afterEach(() => {
    __resetDbForTests();
    if (prevEnv === undefined) delete process.env.ORK_SESSION_DB;
    else process.env.ORK_SESSION_DB = prevEnv;
    rmSync(workDir, { recursive: true, force: true });
  });

  it('marks the session as completed + stamps ended_at', () => {
    const before = Math.floor(Date.now() / 1000);
    const res = sessionFinalizer(makeInput('s-end'), NOOP_CTX);
    expect(res.continue).toBe(true);

    const db = new Database(dbPath, { readonly: true });
    const row = db
      .prepare('SELECT status, ended_at FROM sessions WHERE sid=?')
      .get('s-end') as { status: string; ended_at: number };
    db.close();
    expect(row.status).toBe('completed');
    expect(row.ended_at).toBeGreaterThanOrEqual(before);
  });

  it('is a no-op for an unknown sid (UPDATE matches zero rows)', () => {
    const res = sessionFinalizer(makeInput('s-unknown'), NOOP_CTX);
    expect(res.continue).toBe(true);

    const db = new Database(dbPath, { readonly: true });
    const row = db
      .prepare('SELECT status FROM sessions WHERE sid=?')
      .get('s-end') as { status: string };
    db.close();
    // s-end still running because nothing matched s-unknown.
    expect(row.status).toBe('running');
  });
});
